package teleport

import (
	"context"
	"encoding/base64"
	"testing"

	"github.com/jonboulle/clockwork"
	"github.com/stretchr/testify/require"

	"github.com/gravitational/teleport"
	"github.com/gravitational/teleport/api/client/proto"
	"github.com/gravitational/teleport/api/types"
	"github.com/gravitational/teleport/lib/auth"
	"github.com/gravitational/teleport/lib/auth/mocku2f"
	"github.com/gravitational/teleport/lib/auth/u2f"
	"github.com/gravitational/teleport/lib/services"
)

// TestRegression demonstrates the multi-device U2F authentication bug.
// When a user registers multiple U2F tokens, the authentication challenge
// generation may not include all devices, limiting which hardware tokens
// can be used during login.
func TestRegression(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()

	// Create test auth server with U2F enabled
	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err)

	// Create a test TLS server for gRPC communication
	srv, err := as.NewTestTLSServer()
	require.NoError(t, err)

	// Set up U2F configuration
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.Local,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err)
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err)

	// Create test user
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "testuser", []string{"role"})
	require.NoError(t, err)
	username := user.GetName()

	// Create a gRPC client for the user
	cl, err := srv.NewClient(auth.TestUser(username))
	require.NoError(t, err)

	// ========== SETUP: Register First U2F Device ==========
	u2fDev1, err := mocku2f.Create()
	require.NoError(t, err)

	// Add first U2F device via gRPC stream
	addStream1, err := cl.AddMFADevice(ctx)
	require.NoError(t, err)

	err = addStream1.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_Init{
			Init: &proto.AddMFADeviceRequestInit{
				DeviceName: "u2f-device-1",
				Type:       proto.AddMFADeviceRequestInit_U2F,
			},
		},
	})
	require.NoError(t, err)

	// Receive auth challenge (should be empty for first device)
	authChallenge1, err := addStream1.Recv()
	require.NoError(t, err)
	existingMFAChallenge1 := authChallenge1.GetExistingMFAChallenge()
	require.NotNil(t, existingMFAChallenge1)

	// Send empty auth response since no existing devices
	err = addStream1.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_ExistingMFAResponse{
			ExistingMFAResponse: &proto.MFAAuthenticateResponse{},
		},
	})
	require.NoError(t, err)

	// Receive register challenge
	regChallenge, err := addStream1.Recv()
	require.NoError(t, err)
	u2fRegChallenge := regChallenge.GetNewMFARegisterChallenge().GetU2F()
	require.NotNil(t, u2fRegChallenge)

	// Generate registration response using the server's challenge
	regResp1, err := u2fDev1.RegisterResponse(&u2f.RegisterChallenge{
		Challenge: u2fRegChallenge.Challenge,
		AppID:     u2fRegChallenge.AppID,
	})
	require.NoError(t, err)

	// Send registration response
	err = addStream1.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_NewMFARegisterResponse{
			NewMFARegisterResponse: &proto.MFARegisterResponse{
				Response: &proto.MFARegisterResponse_U2F{
					U2F: &proto.U2FRegisterResponse{
						RegistrationData: regResp1.RegistrationData,
						ClientData:       regResp1.ClientData,
					},
				},
			},
		},
	})
	require.NoError(t, err)

	// Receive ack
	ack1, err := addStream1.Recv()
	require.NoError(t, err)
	require.NotNil(t, ack1.GetAck())

	err = addStream1.CloseSend()
	require.NoError(t, err)

	// ========== SETUP: Register Second U2F Device ==========
	u2fDev2, err := mocku2f.Create()
	require.NoError(t, err)

	// Add second U2F device via gRPC stream
	addStream2, err := cl.AddMFADevice(ctx)
	require.NoError(t, err)

	err = addStream2.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_Init{
			Init: &proto.AddMFADeviceRequestInit{
				DeviceName: "u2f-device-2",
				Type:       proto.AddMFADeviceRequestInit_U2F,
			},
		},
	})
	require.NoError(t, err)

	// Receive auth challenge (now should contain challenge for device 1)
	authChallenge2, err := addStream2.Recv()
	require.NoError(t, err)
	existingMFAChallenge2 := authChallenge2.GetExistingMFAChallenge()
	require.NotNil(t, existingMFAChallenge2)

	// THIS IS THE BUG: When adding a second U2F device,
	// existingMFAChallenge2.U2F should contain challenges for all existing U2F devices
	// In the buggy code, it will only contain ONE challenge even though we have 1 registered device
	// which is correct for this case, but demonstrates the structural issue.

	// Let's verify by checking the content
	u2fChallengesForSecondAdd := len(existingMFAChallenge2.U2F)
	expectedChallengesForSecondAdd := 1 // We've registered 1 device so far

	if u2fChallengesForSecondAdd != expectedChallengesForSecondAdd {
		t.Logf("WARNING: When adding second device, expected %d U2F challenges, got %d",
			expectedChallengesForSecondAdd, u2fChallengesForSecondAdd)
	}

	// Send response using device 1
	if len(existingMFAChallenge2.U2F) > 0 {
		authResp2, err := u2fDev1.SignResponse(&u2f.AuthenticateChallenge{
			Challenge: existingMFAChallenge2.U2F[0].Challenge,
			KeyHandle: existingMFAChallenge2.U2F[0].KeyHandle,
			AppID:     existingMFAChallenge2.U2F[0].AppID,
		})
		require.NoError(t, err)

		err = addStream2.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_ExistingMFAResponse{
				ExistingMFAResponse: &proto.MFAAuthenticateResponse{
					Response: &proto.MFAAuthenticateResponse_U2F{
						U2F: &proto.U2FResponse{
							KeyHandle:  authResp2.KeyHandle,
							ClientData: authResp2.ClientData,
							Signature:  authResp2.SignatureData,
						},
					},
				},
			},
		})
		require.NoError(t, err)
	}

	// Receive register challenge for device 2
	regChallenge2Recv, err := addStream2.Recv()
	require.NoError(t, err)
	u2fRegChallenge2 := regChallenge2Recv.GetNewMFARegisterChallenge().GetU2F()
	require.NotNil(t, u2fRegChallenge2)

	// Generate registration response using the server's challenge
	regResp2, err := u2fDev2.RegisterResponse(&u2f.RegisterChallenge{
		Challenge: u2fRegChallenge2.Challenge,
		AppID:     u2fRegChallenge2.AppID,
	})
	require.NoError(t, err)

	// Send registration response
	err = addStream2.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_NewMFARegisterResponse{
			NewMFARegisterResponse: &proto.MFARegisterResponse{
				Response: &proto.MFARegisterResponse_U2F{
					U2F: &proto.U2FRegisterResponse{
						RegistrationData: regResp2.RegistrationData,
						ClientData:       regResp2.ClientData,
					},
				},
			},
		},
	})
	require.NoError(t, err)

	// Receive ack
	ack2, err := addStream2.Recv()
	require.NoError(t, err)
	require.NotNil(t, ack2.GetAck())

	err = addStream2.CloseSend()
	require.NoError(t, err)

	// ========== REGRESSION TEST: Delete a Device with 2 U2F Devices Present ==========
	// Now we have 2 U2F devices registered.
	// When attempting to delete a device, the auth challenge should contain
	// challenges for ALL existing U2F devices.

	// Verify both devices are registered
	devicesResp, err := cl.GetMFADevices(ctx, &proto.GetMFADevicesRequest{})
	require.NoError(t, err)
	u2fDeviceCount := 0
	for _, dev := range devicesResp.Devices {
		if dev.GetU2F() != nil {
			u2fDeviceCount++
		}
	}
	require.Equal(t, 2, u2fDeviceCount, "Expected 2 U2F devices to be registered")

	// Attempt to delete one of the U2F devices
	deleteStream, err := cl.DeleteMFADevice(ctx)
	require.NoError(t, err)

	err = deleteStream.Send(&proto.DeleteMFADeviceRequest{
		Request: &proto.DeleteMFADeviceRequest_Init{
			Init: &proto.DeleteMFADeviceRequestInit{
				DeviceName: "u2f-device-1",
			},
		},
	})
	require.NoError(t, err)

	// Receive auth challenge
	deleteAuthChallenge, err := deleteStream.Recv()
	require.NoError(t, err)
	deleteChallenge := deleteAuthChallenge.GetMFAChallenge()
	require.NotNil(t, deleteChallenge)

	// ========== REGRESSION BUG DETECTION ==========
	// This is the key regression test:
	// With 2 U2F devices registered, the authentication challenge should contain
	// challenges for BOTH devices so the user can choose which token to use.
	// In the buggy code, the challenge might only include 1 device.

	actualU2FChallengeCount := len(deleteChallenge.U2F)
	expectedU2FChallengeCount := 2 // We have 2 U2F devices

	if actualU2FChallengeCount != expectedU2FChallengeCount {
		t.Logf("REGRESSION BUG DETECTED:")
		t.Logf("With %d U2F devices registered, the authentication challenge should contain %d U2F challenges",
			expectedU2FChallengeCount, expectedU2FChallengeCount)
		t.Logf("Got %d U2F challenges instead", actualU2FChallengeCount)
		t.Logf("This means only %d/%d registered U2F devices can be selected during authentication",
			actualU2FChallengeCount, expectedU2FChallengeCount)

		// Fail if the number doesn't match
		t.Errorf("Multi-device U2F authentication regression: expected %d U2F challenges, got %d",
			expectedU2FChallengeCount, actualU2FChallengeCount)
	}

	// Verify that the challenges are for different devices (not duplicates)
	challengeKeyHandles := make(map[string]bool)
	for _, ch := range deleteChallenge.U2F {
		challengeKeyHandles[ch.KeyHandle] = true
	}

